const stdout = $input.first().json.stdout || '';
const lines = stdout.split('\n').filter(function(l) { return l.trim().charAt(0) === '{'; });
const containers = [];

function parsePorts(portsStr) {
  if (!portsStr) return [];
  const seen = new Set();
  const result = [];
  const parts = portsStr.split(',');
  for (let i = 0; i < parts.length; i++) {
    const p = parts[i].trim();
    const arrowIdx = p.indexOf('->');
    if (arrowIdx < 0) continue;
    const right = p.slice(arrowIdx + 2);
    const slashIdx = right.indexOf('/');
    if (slashIdx < 0) continue;
    const containerPort = parseInt(right.slice(0, slashIdx));
    const protocol = right.slice(slashIdx + 1).toUpperCase().trim();
    const key = containerPort + '/' + protocol;
    if (!seen.has(key) && !isNaN(containerPort)) {
      seen.add(key);
      const left = p.slice(0, arrowIdx);
      const colonIdx = left.lastIndexOf(':');
      const hostPort = colonIdx >= 0 ? parseInt(left.slice(colonIdx + 1)) : 0;
      result.push({ host_port: hostPort, container_port: containerPort, protocol: protocol });
    }
  }
  return result;
}

for (let i = 0; i < lines.length; i++) {
  try {
    const c = JSON.parse(lines[i]);
    const name = (c.name || '');
    containers.push({
      name: name.charAt(0) === '/' ? name.slice(1) : name,
      image: c.image || '',
      state: c.state || '',
      status: c.status || '',
      ports: parsePorts(c.ports),
      container_id: c.id || ''
    });
  } catch(e) {}
}

return [{ json: { containers: containers, collected_at: new Date().toISOString() } }];

