};

async function nbGet(path, params) {
  let url = netbox_url + '/api/' + path + '/?limit=500';
  if (params) {
    const keys = Object.keys(params);
    for (let i = 0; i < keys.length; i++) {
      url += '&' + encodeURIComponent(keys[i]) + '=' + encodeURIComponent(params[keys[i]]);
    }
  }
  return await $helpers.httpRequest({ method: 'GET', url: url, headers: headers });
}

async function nbPost(path, body) {
  return await $helpers.httpRequest({
    method: 'POST',
    url: netbox_url + '/api/' + path + '/',
    headers: headers,
    body: JSON.stringify(body)
  });
}

async function upsert(path, searchParams, createBody) {
  const r = await nbGet(path, searchParams);
  if (r.count > 0) return r.results[0];
  return await nbPost(path, createBody);
}

