const d = $input.first().json;
const netbox_url = d.netbox_url;
const netbox_token = d.netbox_token;
const cluster = d.cluster;
const containers = d.containers;
const collected_at = d.collected_at;
const headers = {
  'Authorization': 'Token ' + netbox_token,
  'Content-Type': 'application/json',
  'Accept': 'application/json'
};

const existingResp = await $helpers.httpRequest({
  method: 'GET',
  url: netbox_url + '/api/virtualization/virtual-machines/?cluster_id=' + cluster.id + '&limit=1000',
  headers: headers
});

const existingByName = {};
for (let i = 0; i < existingResp.results.length; i++) {
  const vm = existingResp.results[i];
  existingByName[vm.name] = vm;
}

const containerNames = {};
for (let i = 0; i < containers.length; i++) {
  containerNames[containers[i].name] = true;
}

const toCreate = [];
const toUpdate = [];
const toMarkOffline = [];

for (let i = 0; i < containers.length; i++) {
  const c = containers[i];
  const vmStatus = c.state === 'running' ? 'active' : 'offline';
  const vmData = {
    name: c.name,
    cluster: { id: cluster.id },
    status: vmStatus,
    comments: 'Image: ' + c.image + ' | Synced: ' + collected_at
  };
  if (existingByName[c.name]) {
    const update = {
      id: existingByName[c.name].id,
      name: vmData.name,
      cluster: vmData.cluster,
      status: vmData.status,
      comments: vmData.comments
    };
    toUpdate.push(update);
  } else {
    toCreate.push(vmData);
  }
}

for (let i = 0; i < existingResp.results.length; i++) {
  const vm = existingResp.results[i];
  const statusVal = vm.status && vm.status.value ? vm.status.value : vm.status;
  if (!containerNames[vm.name] && statusVal !== 'offline') {
    toMarkOffline.push({ id: vm.id, status: 'offline' });
  }
}

let created = [];
if (toCreate.length > 0) {
  const resp = await $helpers.httpRequest({
    method: 'POST',
    url: netbox_url + '/api/virtualization/virtual-machines/',
    headers: headers,
    body: JSON.stringify(toCreate)
  });
  created = Array.isArray(resp) ? resp : [resp];
}

let updated = [];
if (toUpdate.length > 0) {
  const resp = await $helpers.httpRequest({
    method: 'PATCH',
    url: netbox_url + '/api/virtualization/virtual-machines/',
    headers: headers,
    body: JSON.stringify(toUpdate)
  });
  updated = Array.isArray(resp) ? resp : [resp];
}

if (toMarkOffline.length > 0) {
  await $helpers.httpRequest({
    method: 'PATCH',
    url: netbox_url + '/api/virtualization/virtual-machines/',
    headers: headers,
    body: JSON.stringify(toMarkOffline)
  });
}

const vmByName = {};
for (let i = 0; i < created.length; i++) {
  if (created[i] && created[i].name) vmByName[created[i].name] = created[i];
}
for (let i = 0; i < toUpdate.length; i++) {
  const name = toUpdate[i].name;
  if (existingByName[name]) vmByName[name] = existingByName[name];
}
for (let i = 0; i < containers.length; i++) {
  const name = containers[i].name;
  if (!vmByName[name] && existingByName[name]) vmByName[name] = existingByName[name];
}

return [{
  json: {
    containers: d.containers,
    collected_at: d.collected_at,
    netbox_url: d.netbox_url,
    netbox_token: d.netbox_token,
    site: d.site,
    cluster_type: d.cluster_type,
    cluster: d.cluster,
    vmByName: vmByName,
    vm_sync: {
      created: toCreate.length,
      updated: toUpdate.length,
      marked_offline: toMarkOffline.length
    }
  }
}];

const d = $input.first().json;
const netbox_url = d.netbox_url;
const netbox_token = d.netbox_token;
const containers = d.containers;
const vmByName = d.vmByName;
const headers = {
  'Authorization': 'Token ' + netbox_token,
  'Content-Type': 'application/json',
  'Accept': 'application/json'
};

let servicesCreated = 0;
let servicesUpdated = 0;

for (let i = 0; i < containers.length; i++) {
  const c = containers[i];
  if (!c.ports || c.ports.length === 0) continue;
  const vm = vmByName[c.name];
  if (!vm) continue;

  const existingResp = await $helpers.httpRequest({
    method: 'GET',
    url: netbox_url + '/api/ipam/services/?virtual_machine_id=' + vm.id + '&limit=100',
    headers: headers
  });

  const existingByKey = {};
  for (let j = 0; j < existingResp.results.length; j++) {
    const svc = existingResp.results[j];
    if (svc.ports && svc.ports.length > 0) {
      const protoVal = svc.protocol && svc.protocol.value ? svc.protocol.value : svc.protocol;
      const key = svc.ports[0] + '-' + protoVal;
      existingByKey[key] = svc;
    }
  }

  for (let j = 0; j < c.ports.length; j++) {
    const p = c.ports[j];
    const proto = p.protocol.toLowerCase();
    const key = p.container_port + '-' + proto;
    const svcName = c.name + ':' + p.container_port + '/' + proto;
    if (existingByKey[key]) {
      await $helpers.httpRequest({
        method: 'PATCH',
        url: netbox_url + '/api/ipam/services/' + existingByKey[key].id + '/',
        headers: headers,
        body: JSON.stringify({ name: svcName, ports: [p.container_port], protocol: proto })
      });
      servicesUpdated++;
    } else {
      await $helpers.httpRequest({
        method: 'POST',
        url: netbox_url + '/api/ipam/services/',
        headers: headers,
        body: JSON.stringify({
          virtual_machine: vm.id,
          name: svcName,
          ports: [p.container_port],
          protocol: proto
        })
      });
      servicesCreated++;
    }
  }
}

return [{
  json: {
    containers: d.containers,
    collected_at: d.collected_at,
    netbox_url: d.netbox_url,
    netbox_token: d.netbox_token,
    site: d.site,
    cluster_type: d.cluster_type,
    cluster: d.cluster,
    vmByName: d.vmByName,
    vm_sync: d.vm_sync,
    services_sync: { created: servicesCreated, updated: servicesUpdated }
  }
}];

const d = $input.first().json;
