const knownPrefixes = [
  { prefix: '172.20.0.0/24', description: 'homelab-net Docker network', status: 'active' },
  { prefix: '10.0.10.0/24', description: 'Lab LAN (lab.home domain)', status: 'active' },
  { prefix: '10.8.0.0/24', description: 'WireGuard VPN tunnel', status: 'active' },
  { prefix: '172.17.0.0/16', description: 'Docker default bridge (docker0)', status: 'reserved' },
  { prefix: '10.10.10.0/24', description: 'Kubernetes cluster nodes (k8s-prod)', status: 'active' },
  { prefix: '10.244.0.0/16', description: 'Kubernetes pod CIDR (Calico CNI)', status: 'active' },
  { prefix: '10.96.0.0/12', description: 'Kubernetes service CIDR', status: 'active' }
];

let prefixesCreated = 0;
let prefixesExisting = 0;

for (let i = 0; i < knownPrefixes.length; i++) {
  const p = knownPrefixes[i];
  const result = await $helpers.httpRequest({
    method: 'GET',
    url: netbox_url + '/api/ipam/prefixes/?prefix=' + encodeURIComponent(p.prefix),
    headers: headers
  });

  if (result.count === 0) {
    await $helpers.httpRequest({
      method: 'POST',
      url: netbox_url + '/api/ipam/prefixes/',
      headers: headers,
      body: JSON.stringify({
        prefix: p.prefix,
        description: p.description,
        status: p.status,
        site: { id: site.id }
      })
    });
    prefixesCreated++;
  } else {
    prefixesExisting++;
  }
}

return [{
  json: {
    containers_found: d.containers.length,
    vm_sync: d.vm_sync,
    services_sync: d.services_sync,
    prefixes_sync: { created: prefixesCreated, existing: prefixesExisting }
  }
}];

const config = $('Set: Configuration').first().json;
const netbox_url = config.netbox_url;
const netbox_token = config.netbox_token;
const librenms_url = config.librenms_url;
const librenms_token = config.librenms_token;
const site = $('Code: Ensure Netbox Infrastructure').first().json.site;
const nbH = {
  'Authorization': 'Token ' + netbox_token,
  'Content-Type': 'application/json',
  'Accept': 'application/json'
};
const lnmH = { 'X-Auth-Token': librenms_token, 'Accept': 'application/json' };

async function nbGet(path, params) {
  let url = netbox_url + '/api/' + path + '/?limit=500';
  if (params) {
    const keys = Object.keys(params);
    for (let i = 0; i < keys.length; i++) {
      url += '&' + encodeURIComponent(keys[i]) + '=' + encodeURIComponent(params[keys[i]]);
    }
  }
  return await $helpers.httpRequest({ method: 'GET', url: url, headers: nbH });
}

async function nbPost(path, body) {
  return await $helpers.httpRequest({
    method: 'POST',
    url: netbox_url + '/api/' + path + '/',
    headers: nbH,
    body: JSON.stringify(body)
  });
}

async function upsert(path, searchParams, createBody) {
  const r = await nbGet(path, searchParams);
  if (r.count > 0) return r.results[0];
  return await nbPost(path, createBody);
}

// Pull all SNMP-discovered physical devices from LibreNMS
let lnmDevices = [];
try {
  const resp = await $helpers.httpRequest({ method: 'GET', url: librenms_url + '/api/v0/devices', headers: lnmH });
  lnmDevices = resp.devices || [];
} catch(e) {}

function guessRoleSlug(os, descr) {
  const s = (os + ' ' + descr).toLowerCase();
  if (s.includes('proxmox') || s.includes('pve')) return 'hypervisor';
  if (s.includes('switch') || s.includes('cisco') || s.includes('junos') || s.includes('cumulus')) return 'network-switch';
  if (s.includes('router') || s.includes('gateway') || s.includes('openwrt') || s.includes('vyos')) return 'gateway';
  if (s.includes('nas') || s.includes('truenas') || s.includes('freenas') || s.includes('synology')) return 'nas';
  return 'server';
}

const roleLabels = {
  'server': 'Server',
  'hypervisor': 'Hypervisor',
  'network-switch': 'Network Switch',
  'gateway': 'Gateway',
  'nas': 'NAS'
};

const manufacturer = await upsert('dcim/manufacturers', { slug: 'generic' }, {
  name: 'Generic',
  slug: 'generic'
});

const devicesByName = {};

for (let i = 0; i < lnmDevices.length; i++) {
  const d = lnmDevices[i];
  const devName = d.sysName || d.hostname;
  if (!devName) continue;

  const roleSlug = guessRoleSlug(d.os || '', d.sysDescr || '');
  const role = await upsert('dcim/device-roles', { slug: roleSlug }, {
    name: roleLabels[roleSlug],
    slug: roleSlug,
    color: '0d6efd'
  });

  const hwRaw = (d.hardware || 'Generic Server').slice(0, 50);
  const hwSlug = hwRaw.toLowerCase().split(' ').filter(Boolean).join('-').slice(0, 50);
  const deviceType = await upsert('dcim/device-types', { slug: hwSlug }, {
    manufacturer: { id: manufacturer.id },
    model: hwRaw,
    slug: hwSlug
  });

  const device = await upsert('dcim/devices', { name: devName }, {
    name: devName,
    device_type: { id: deviceType.id },
    role: { id: role.id },
    site: { id: site.id },
    status: d.status === 1 ? 'active' : 'offline',
    comments: 'OS: ' + (d.os || 'unknown') + ' | IP: ' + (d.ip || '') + ' | Synced from LibreNMS'
  });

  devicesByName[devName] = { nb: device, lnm: d };
}

return [{ json: { devicesByName: devicesByName, devices_sync: { synced: Object.keys(devicesByName).length } } }];

