// Map Linux/SNMP interface name to Netbox interface type
function mapIfType(name) {
  const n = name.toLowerCase();
  if (n.startsWith('eth') || n.startsWith('ens') || n.startsWith('enp') || n.startsWith('eno')) return '1000base-t';
  if (n.startsWith('lo')) return 'virtual';
  if (n.startsWith('bond') || n.startsWith('team')) return 'lag';
  if (n.startsWith('br') || n.startsWith('docker') || n.startsWith('virbr')) return 'bridge';
  if (n.startsWith('wg') || n.startsWith('tun') || n.startsWith('vpn')) return 'virtual';
  if (n.startsWith('wlan') || n.startsWith('wlp')) return '802.11n';
  if (n.startsWith('sfp') || n.startsWith('xe') || n.startsWith('te')) return '10gbase-t';
  if (n.startsWith('ge-') || n.startsWith('gi')) return '1000base-t';
  return 'other';
}

const interfacesByKey = {};
let ifaceCount = 0;

const devNames = Object.keys(devicesByName);
for (let i = 0; i < devNames.length; i++) {
  const devName = devNames[i];
  const entry = devicesByName[devName];
  const device = entry.nb;
  const lnmDev = entry.lnm;

  let ports = [];
  try {
    const resp = await $helpers.httpRequest({
      method: 'GET',
      url: librenms_url + '/api/v0/devices/' + encodeURIComponent(lnmDev.hostname) + '/ports?columns=port_id,ifName,ifAlias,ifSpeed,ifOperStatus,ifPhysAddress',
      headers: lnmH
    });
    ports = resp.ports || [];
  } catch(e) {}

  for (let j = 0; j < ports.length; j++) {
    const port = ports[j];
    const ifName = port.ifName || ('if' + j);
    const mac = (port.ifPhysAddress && port.ifPhysAddress.length > 0) ? port.ifPhysAddress : null;

    const iface = await upsert('dcim/interfaces', { device_id: device.id, name: ifName }, {
      device: { id: device.id },
      name: ifName,
      type: mapIfType(ifName),
      label: port.ifAlias || '',
      enabled: port.ifOperStatus === 'up',
      mac_address: mac,
      description: 'LibreNMS port_id=' + port.port_id
    });

    interfacesByKey[devName + ':' + ifName] = { nb: iface, port_id: String(port.port_id) };
    ifaceCount++;
  }
}

return [{ json: { devicesByName: devicesByName, interfacesByKey: interfacesByKey, interfaces_sync: { synced: ifaceCount } } }];

const config = $('Set: Configuration').first().json;
const netbox_url = config.netbox_url;
const netbox_token = config.netbox_token;
const librenms_url = config.librenms_url;
const librenms_token = config.librenms_token;
const interfacesByKey = $input.first().json.interfacesByKey;
const nbH = {
  'Authorization': 'Token ' + netbox_token,
  'Content-Type': 'application/json',
  'Accept': 'application/json'
};
const lnmH = { 'X-Auth-Token': librenms_token, 'Accept': 'application/json' };

// Fetch LLDP topology from LibreNMS — each link is a physical cable between two interfaces
let links = [];
try {
  const resp = await $helpers.httpRequest({ method: 'GET', url: librenms_url + '/api/v0/links', headers: lnmH });
  links = resp.links || [];
} catch(e) {}

// Load all existing cables so we do not create duplicates
const cablesResp = await $helpers.httpRequest({
  method: 'GET',
  url: netbox_url + '/api/dcim/cables/?limit=1000',
  headers: nbH
});

const existingPairs = new Set();
for (let i = 0; i < cablesResp.results.length; i++) {
  const c = cablesResp.results[i];
  if (c.a_terminations && c.b_terminations && c.a_terminations.length > 0 && c.b_terminations.length > 0) {
    const aId = c.a_terminations[0].object_id;
    const bId = c.b_terminations[0].object_id;
    existingPairs.add(aId + '-' + bId);
    existingPairs.add(bId + '-' + aId);
  }
}

// Build reverse index: LibreNMS port_id -> interfacesByKey entry
const portIdToKey = {};
const ifKeys = Object.keys(interfacesByKey);
for (let i = 0; i < ifKeys.length; i++) {
  const entry = interfacesByKey[ifKeys[i]];
  if (entry.port_id) portIdToKey[entry.port_id] = ifKeys[i];
}

let cablesCreated = 0;
let cablesSkipped = 0;

for (let i = 0; i < links.length; i++) {
  const link = links[i];
  const localKey = portIdToKey[String(link.local_port_id)];
  const remoteKey = portIdToKey[String(link.remote_port_id)];
  if (!localKey || !remoteKey) { cablesSkipped++; continue; }

  const localIfId = interfacesByKey[localKey].nb.id;
  const remoteIfId = interfacesByKey[remoteKey].nb.id;
  const pairKey = localIfId + '-' + remoteIfId;
  if (existingPairs.has(pairKey)) { cablesSkipped++; continue; }

  try {
    await $helpers.httpRequest({
      method: 'POST',
      url: netbox_url + '/api/dcim/cables/',
      headers: nbH,
      body: JSON.stringify({
        a_terminations: [{ object_type: 'dcim.interface', object_id: localIfId }],
        b_terminations: [{ object_type: 'dcim.interface', object_id: remoteIfId }],
        status: 'connected',
        type: 'cat6'
      })
    });
    existingPairs.add(pairKey);
    existingPairs.add(remoteIfId + '-' + localIfId);
    cablesCreated++;
  } catch(e) { cablesSkipped++; }
}

return [{
  json: {
    sync_completed_at: new Date().toISOString(),
    devices_sync: $('Code: Sync Physical Devices').first().json.devices_sync,
    interfaces_sync: $input.first().json.interfaces_sync,
    cables_sync: { created: cablesCreated, skipped: cablesSkipped }
  }
}];
